export function getResortBySlug(slug) {
  return resorts.find((r) => r.slug === slug) || null
}

export function getResortsByType(type) {
  return resorts.filter((r) => r.type === type)
}

export function getResortsByCountry(countrySlug) {
  return resorts.filter((r) => r.countrySlug === countrySlug)
}

export function getAllCountries() {
  const seen = new Set()
  return resorts
    .filter((r) => {
      if (seen.has(r.countrySlug)) return false
      seen.add(r.countrySlug)
      return true
    })
    .map((r) => ({ name: r.country, slug: r.countrySlug }))
}

export function getAllComparisonPairs() {
  const pairs = []
  for (let i = 0; i < resorts.length; i++) {
    for (let j = i + 1; j < resorts.length; j++) {
      const x = resorts[i]
      const y = resorts[j]
      // Always put the alphabetically-first slug as 'a' so URLs are consistent everywhere
      const [a, b] = x.slug < y.slug ? [x, y] : [y, x]
      pairs.push({ a, b })
    }
  }
  return pairs
}

export function getTopByRating(key, count = 5) {
  return [...resorts]
    .filter((r) => r.ratings[key] !== null)
    .sort((a, b) => (b.ratings[key] || 0) - (a.ratings[key] || 0))
    .slice(0, count)
}
